from pathlib import Path
from datetime import date, timedelta
import csv

ref = date(2025, 8, 12)
periods = {
    'today': lambda d: d == ref,
    'last_7_days': lambda d: ref - timedelta(days=6) <= d <= ref,
    'last_30_days': lambda d: ref - timedelta(days=29) <= d <= ref,
    'month_to_date': lambda d: date(ref.year, ref.month, 1) <= d <= ref,
    'total': lambda d: True,
}
severities = ['ERROR', 'WARNING', 'INFO']
counts = {p: {s: 0 for s in severities} for p in periods}

for path in sorted(Path('/app/logs').glob('*.log')):
    stem = path.name.split('_', 1)[0]
    try:
        y, m, d = map(int, stem.split('-'))
        file_date = date(y, m, d)
    except Exception:
        continue
    memberships = [p for p, pred in periods.items() if pred(file_date)]
    if not memberships:
        continue
    with path.open('r', encoding='utf-8') as f:
        for line in f:
            matched = None
            for sev in severities:
                if f'[{sev}]' in line:
                    matched = sev
                    break
            if matched is None:
                continue
            for p in memberships:
                counts[p][matched] += 1

rows = [('period','severity','count')]
for period in ['today', 'last_7_days', 'last_30_days', 'month_to_date', 'total']:
    for sev in severities:
        rows.append((period, sev, str(counts[period][sev])))

with open('/app/summary.csv', 'w', newline='', encoding='utf-8') as f:
    writer = csv.writer(f)
    writer.writerows(rows)
